/* ─── UTILS ──────────────────────────────────────────────────────── */
function getURLParam(k) {
  try { return new URLSearchParams(window.location.search).get(k) || ""; } catch { return ""; }
}

async function saveToSupabase(payload) {
  try {
    if (!CFG.supabaseUrl || !CFG.supabaseKey) { console.warn("Supabase no configurado"); return null; }
    const r = await fetch(`${CFG.supabaseUrl}/rest/v1/appdiagnostico`, {
      method:"POST",
      headers:{ "Content-Type":"application/json", "apikey":CFG.supabaseKey, "Authorization":`Bearer ${CFG.supabaseKey}`, "Prefer":"return=representation" },
      body: JSON.stringify(payload),
    });
    if (!r.ok) { console.error("Supabase error:", r.status, await r.text()); return null; }
    const d = await r.json();
    return d?.[0]?.id || null;
  } catch (err) { console.error("saveToSupabase:", err); return null; }
}

async function triggerN8N(payload) {
  try {
    if (!CFG.n8nWebhook) { console.warn("N8N webhook no configurado"); return; }
    const r = await fetch(CFG.n8nWebhook, { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify(payload) });
    if (!r.ok) console.error("N8N webhook error:", r.status);
  } catch (err) { console.error("triggerN8N:", err); }
}

