/* ─── SCORE RING ─────────────────────────────────────────────────── */
function ScoreRing({ score, color, size=120 }) {
  const ref = useRef(null);
  useEffect(()=>{
    const cv=ref.current; if(!cv)return;
    const ctx=cv.getContext("2d"), cx=size/2,cy=size/2,r=size/2-9,lw=8;
    ctx.clearRect(0,0,size,size);
    ctx.beginPath(); ctx.arc(cx,cy,r,0,Math.PI*2);
    ctx.strokeStyle="rgba(27,79,216,0.08)"; ctx.lineWidth=lw; ctx.stroke();
    const angle=(score/100)*Math.PI*2-Math.PI/2;
    const g=ctx.createLinearGradient(0,0,size,size);
    g.addColorStop(0,T.grad1); g.addColorStop(1,T.grad2);
    ctx.beginPath(); ctx.arc(cx,cy,r,-Math.PI/2,angle);
    ctx.strokeStyle=g; ctx.lineWidth=lw; ctx.lineCap="round"; ctx.stroke();
  },[score,color,size]);
  return (
    <div style={{ position:"relative",width:size,height:size }}>
      <canvas ref={ref} width={size} height={size} style={{ position:"absolute",top:0,left:0 }} />
      <div style={{ position:"absolute",top:"50%",left:"50%",transform:"translate(-50%,-50%)",textAlign:"center" }}>
        <div style={{ fontSize:26,fontWeight:700,color:T.text,lineHeight:1 }}>{score}</div>
        <div style={{ fontSize:11,color:T.textMut,marginTop:1 }}>/ 100</div>
      </div>
    </div>
  );
}

